      "KeySymbols": [
        "Event",
        "InventoryLibrary",
        "InventoryHistory",
        "get_engine"
      ]
    },
    {
      "FilePath": "src/scheduler/main.py",
      "Reasoning": "Manages background tasks. Uses an in-memory job store and manual rescheduling logic which could be improved for reliability.",
      "KeySymbols": [
        "MovieHubScheduler",
        "update_event_inventory",
        "main_discovery_job"
      ]
    },
    {
      "FilePath": "src/utils/notifier.py",
      "Reasoning": "Handles notifications. Currently tightly coupled to Telegram and lacks abstraction for other platforms.",
      "KeySymbols": [
        "TelegramNotifier"
      ]
    },
    {
      "FilePath": "src/web/templates/index.html",
      "Reasoning": "Main dashboard template. UI logic (like operator badges) is somewhat repetitive and could be improved with better components.",
      "KeySymbols": []
    }
  ]
}

